esqlQuery.esql:
// Alert when the IPA API error rate exceeds a threshold.
// A spike in API errors may indicate backend issues (LDAP unreachable,
// plugin failure, schema conflict after upgrade).
// Adjust the error count threshold in the final WHERE clause as needed.
FROM logs-freeipa.ipa_api-*
| WHERE event.outcome == "failure"
| STATS error_count = COUNT(*), errors = COUNT_DISTINCT(freeipa.api.result) BY freeipa.api.result
| WHERE error_count >= 10
